SmartRisk.TerritoriosModule={route:{path:"/territorios",title:"Territorios",render(){return `<section class="page-header"><div><span class="kicker">Módulo territorial</span><h1 class="page-title">Territorios</h1><p class="page-subtitle">Resumen provincial de la Zona 5.</p></div></section><section class="territory-summary">${SmartRisk.MockData.territories.map(t=>`<article class="territory-summary-card"><span>${t.provincia}</span><strong>${t.avance}%</strong><small class="muted">${t.planes} planes · ${t.cantones} cantones</small></article>`).join("")}</section>`}}};